<div class="ja">
<svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">ブラジル暗号資産規制強化タイムライン</text>
  <g font-family="sans-serif">
    <line x1="50" y1="200" x2="660" y2="200" stroke="#3f3f46" stroke-width="2"/>
    <circle cx="90" cy="200" r="7" fill="#71717a"/>
